<template><el-card><template #header>智能编译任务</template><el-steps :active="5" finish-status="success" align-center><el-step v-for="s in stages" :key="s" :title="s"/></el-steps><DataTable class="mt" :data="rows"><el-table-column prop="name" label="任务名称"/><el-table-column prop="sourceFile" label="来源文件"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="stage" label="当前阶段"/><el-table-column label="进度"><template #default="s"><el-progress :percentage="s.row.progress"/></template></el-table-column><el-table-column prop="creator" label="创建人"/><el-table-column prop="createdAt" label="创建时间"/><el-table-column label="操作" width="220"><template #default="s"><el-button link type="primary" @click="detail=s.row">详情</el-button><el-button link @click="s.row.progress=10;s.row.stage='解析中'">重新编译</el-button><el-button link @click="log=s.row">日志</el-button></template></el-table-column></DataTable><DetailDrawer v-model="open" title="任务详情"><el-tabs><el-tab-pane v-for="i in ['解析结果','元数据抽取结果','Markdown 生成结果','条款切片结果','规则抽取结果','风险提示']" :key="i" :label="i">{{i}}：{{detail?.name}} 模拟内容，流程可追溯。</el-tab-pane></el-tabs></DetailDrawer><el-dialog v-model="logOpen" title="编译日志"><pre>INFO 开始解析\nINFO 提取元数据\nWARN 发现疑似旧版本引用\nINFO 生成知识切片</pre></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { compileTasks } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; const stages=['待解析','解析中','编译中','切片中','规则抽取中','评估中','待审核','已完成','失败']; const rows=ref<any[]>(JSON.parse(JSON.stringify(compileTasks))); const detail=ref<any>(); const log=ref<any>(); const open=computed({get:()=>!!detail.value,set:v=>{if(!v)detail.value=null}}); const logOpen=computed({get:()=>!!log.value,set:v=>{if(!v)log.value=null}});</script>
